import React, { useState } from 'react';
import axios from 'axios';
import { Save, Trash2, Loader2, FileSpreadsheet, Send, Calendar } from 'lucide-react';

const GestionInventario = ({ localId, onComplete }) => {
    const crearFilasVacias = (cant) => Array(cant).fill().map(() => ({
        tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: ''
    }));

    const [filas, setFilas] = useState(crearFilasVacias(10));
    const [loading, setLoading] = useState(false);
    
    // Estado para las fechas de publicación del lote
    const [fechas, setFechas] = useState({ inicio: '', fin: '' });

    const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

    const handlePaste = (e, filaIndex, colIndex) => {
        const pasteData = e.clipboardData.getData('text');
        if (!pasteData) return;

        const rows = pasteData.split(/\r\n|\n|\r/);
        const nuevasFilas = [...filas];

        rows.forEach((rowText, i) => {
            const trimmedRow = rowText.trim();
            if (!trimmedRow) return;

            const targetFilaIndex = filaIndex + i;
            if (!nuevasFilas[targetFilaIndex]) {
                nuevasFilas[targetFilaIndex] = { tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '' };
            }

            const cells = rowText.split('\t');
            cells.forEach((cellText, j) => {
                const targetColIndex = colIndex + j;
                const fieldNames = ['tipo', 'marca', 'contenido', 'categoria', 'precioNuevo', 'precioViejo', 'stock'];
                const fieldName = fieldNames[targetColIndex];
                if (fieldName) nuevasFilas[targetFilaIndex][fieldName] = cellText.trim();
            });
        });

        setFilas(nuevasFilas);
        e.preventDefault();
    };

    const handleInputChange = (index, field, value) => {
        const nuevas = [...filas];
        nuevas[index][field] = value;
        setFilas(nuevas);
    };

    const handlePublicarLote = async () => {
        const validos = filas.filter(f => f.tipo && f.marca && f.precioNuevo);
        
        if (validos.length === 0) {
            return alert("No hay productos válidos para publicar.");
        }
        if (!fechas.inicio || !fechas.fin) {
            return alert("Debes seleccionar Fecha de Inicio y Cierre para publicar el lote.");
        }

        setLoading(true);
        try {
            // Enviamos el lote con estado publicado: true y las fechas asignadas
            await axios.post(`${API_URL}/api/ofertas/bulk`, {
                localId,
                productos: validos.map(p => ({
                    ...p,
                    producto: `${p.tipo} ${p.marca} ${p.contenido}`.trim(),
                    precioNuevo: Number(p.precioNuevo),
                    precioViejo: Number(p.precioViejo) || Number(p.precioNuevo),
                    stock: Number(p.stock) || 0,
                    publicado: true,
                    fechaInicioOferta: fechas.inicio,
                    fechaFinOferta: fechas.fin
                }))
            });
            
            alert(`¡Éxito! Se han publicado ${validos.length} ofertas.`);
            setFilas(crearFilasVacias(10));
            setFechas({ inicio: '', fin: '' });
            onComplete();
        } catch (err) {
            alert("Error al publicar: " + (err.response?.data?.error || err.message));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={container}>
            <div style={header}>
                <div style={{display:'flex', alignItems:'center', gap:'10px'}}>
                    <FileSpreadsheet size={22} color="#107c41" />
                    <h3 style={{margin:0}}>Carga y Publicación Masiva</h3>
                </div>
                <span style={tip}>Copiá en Excel y pegá acá (Ctrl+V)</span>
            </div>

            <div style={tableWrapper}>
                <table style={table}>
                    <thead>
                        <tr style={thr}>
                            <th style={th}>Tipo</th>
                            <th style={th}>Marca</th>
                            <th style={th}>Contenido</th>
                            <th style={th}>Categoría</th>
                            <th style={th}>$ Oferta</th>
                            <th style={th}>$ Normal</th>
                            <th style={th}>Stock</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filas.map((f, i) => (
                            <tr key={i}>
                                {['tipo', 'marca', 'contenido', 'categoria', 'precioNuevo', 'precioViejo', 'stock'].map((field, j) => (
                                    <td key={j} style={td}>
                                        <input
                                            style={input}
                                            value={f[field]}
                                            onChange={(e) => handleInputChange(i, field, e.target.value)}
                                            onPaste={(e) => handlePaste(e, i, j)}
                                            placeholder="..."
                                        />
                                    </td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            <div style={footer}>
                <button onClick={() => setFilas(crearFilasVacias(10))} style={btnSec}>Limpiar Celdas</button>
                
                <div style={publishGroup}>
                    <div style={dateBox}>
                        <label style={dateLabel}><Calendar size={12}/> Inicio:</label>
                        <input 
                            type="date" 
                            style={dateInput} 
                            value={fechas.inicio}
                            onChange={(e) => setFechas({...fechas, inicio: e.target.value})}
                        />
                    </div>
                    <div style={dateBox}>
                        <label style={dateLabel}><Calendar size={12}/> Cierre:</label>
                        <input 
                            type="date" 
                            style={dateInput}
                            value={fechas.fin}
                            onChange={(e) => setFechas({...fechas, fin: e.target.value})}
                        />
                    </div>
                    <button onClick={handlePublicarLote} style={btnPub} disabled={loading}>
                        {loading ? <Loader2 className="animate-spin" size={18}/> : <Send size={18}/>}
                        PUBLICAR LOTE
                    </button>
                </div>
            </div>
        </div>
    );
};

// --- ESTILOS ---
const container = { background: '#fff', borderRadius: '12px', border: '2px solid #e2e8f0', marginBottom: '30px', overflow: 'hidden', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' };
const header = { padding: '15px 20px', background: '#f8fafc', borderBottom: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const tip = { fontSize: '0.75rem', color: '#64748b', fontStyle: 'italic' };
const tableWrapper = { overflowX: 'auto', maxHeight: '450px' };
const table = { width: '100%', borderCollapse: 'collapse' };
const thr = { background: '#f1f5f9' };
const th = { padding: '12px', border: '1px solid #e2e8f0', fontSize: '0.75rem', textAlign: 'left', color: '#475569', fontWeight: '800', textTransform: 'uppercase' };
const td = { border: '1px solid #e2e8f0', padding: 0 };
const input = { width: '100%', padding: '12px 10px', border: 'none', outline: 'none', fontSize: '0.85rem', background: 'transparent' };

const footer = { padding: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#f8fafc', borderTop: '2px solid #e2e8f0' };
const btnSec = { background: '#fff', border: '1px solid #cbd5e1', padding: '10px 15px', borderRadius: '8px', cursor: 'pointer', color: '#64748b', fontWeight: '600' };

const publishGroup = { display: 'flex', alignItems: 'center', gap: '15px', background: '#f1f5f9', padding: '10px 15px', borderRadius: '12px', border: '1px solid #e2e8f0' };
const dateBox = { display: 'flex', flexDirection: 'column', gap: '3px' };
const dateLabel = { fontSize: '0.7rem', fontWeight: '800', color: '#475569', display: 'flex', alignItems: 'center', gap: '4px' };
const dateInput = { padding: '6px', borderRadius: '6px', border: '1px solid #cbd5e1', fontSize: '0.8rem', outline: 'none' };
const btnPub = { background: '#10b981', color: '#fff', border: 'none', padding: '12px 25px', borderRadius: '10px', cursor: 'pointer', fontWeight: '900', display: 'flex', alignItems: 'center', gap: '10px', boxShadow: '0 4px 0 #059669' };

export default GestionInventario;
